function New-Profil {
    param(
        [Parameter(Mandatory)][string]$Nom,
        [int]$Age = 0,
        [string]$Ville = "Non renseignée"
    )
    Write-Host "Nom : $Nom | Age : $Age | Ville : $Ville"
}

New-Profil -Nom "Alice" -Age 25 -Ville "Lyon"
New-Profil -Nom "Bob"

function ConvertTo-Celsius {
    [CmdletBinding()]
    param(
        [Parameter(ValueFromPipeline)]
        [double]$Fahrenheit
    )
    process {
        $celsius = [math]::Round(($Fahrenheit - 32) * 5/9, 1)
        Write-Host "F=$Fahrenheit → C=$celsius"
    }
}

@(32, 212, 98.6) | ConvertTo-Celsius

function Get-Note {
    param(
        [ValidateRange(0, 20)]
        [int]$Note
    )
    switch ($Note) {
        { $_ -ge 16 } { "Très bien"; break }
        { $_ -ge 14 } { "Bien"; break }
        { $_ -ge 12 } { "Assez bien"; break }
        { $_ -ge 10 } { "Passable"; break }
        default        { "Insuffisant" }
    }
}

Get-Note -Note 15
